/**
 * n8n Code node (JavaScript)
 * Merges 2 incoming items into 1, preserving all JSON + binary data.
 */

function isObject(v) {
	return v !== null && typeof v === 'object' && !Array.isArray(v);
}

function deepMerge(a, b) {
	// Arrays: concatenate
	if (Array.isArray(a) && Array.isArray(b)) return [...a, ...b];

	// Objects: recursive merge
	if (isObject(a) && isObject(b)) {
		const out = { ...a };
		for (const [k, v] of Object.entries(b)) {
			if (k in out) out[k] = deepMerge(out[k], v);
			else out[k] = v;
		}
		return out;
	}

	// Fallback: keep both if different by wrapping, else keep b
	if (a === undefined) return b;
	if (b === undefined) return a;
	if (a === b) return a;
	return { _a: a, _b: b };
}

const items = $input.all();

if (items.length < 2) {
	// Nothing to merge; return as-is
	return items;
}

const merged = {
	json: {},
	binary: {},
};

// Merge JSON of all items (works for 2 or more)
for (const item of items) {
	merged.json = deepMerge(merged.json, item.json ?? {});
}

// Merge binary of all items, avoid overwrites
for (let i = 0; i < items.length; i++) {
	const bin = items[i].binary ?? {};
	for (const [key, value] of Object.entries(bin)) {
		if (!(key in merged.binary)) {
			merged.binary[key] = value;
		} else {
			// rename to avoid overwriting existing binary key
			let n = 2;
			let newKey = `${key}_${n}`;
			while (newKey in merged.binary) {
				n++;
				newKey = `${key}_${n}`;
			}
			merged.binary[newKey] = value;
		}
	}
}

return [merged];

